#!/usr/bin/env bash
# topic-1.sh — 续费 决策助手 for K12 体育培训.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="K12 体育培训"
TOPIC="续费"

usage() {
  cat <<EOF
topic-1.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 4 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./topic-1.sh             # interactive
  ./topic-1.sh --dry-run   # walk through but no file
  ./topic-1.sh --json      # JSON to stdout
  ./topic-1.sh --explain   # show backing playbook rules + mental models
  ./topic-1.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 续费 主题下的 playbook 规则组合成交互树。

基于 4 条规则:
  • 如果 要让家长感知价值或驱动续费转介绍 → 则 把测评数据做成可视化成长报告交付，而非只在期末口头汇报。这是跨 4 个 workflow（试听/教学/中考/续费）的元动
  • 如果 课包剩约 1/3 或出现成果节点（一次体测进步/一场比赛） → 则 立即启动续费动作在满意峰值顺势收，绝不到期才催费、更不靠打折逼单。案例：懒熊单店死亡案例续费率从约 46% 跌到接近 0
  • 如果 续费率或出勤率跌破警戒线 → 则 先救留存再谈扩张/获客，绝不靠加大获客投放掩盖留存窟窿。案例：趣动旅程靠预收费扩张、黑天鹅下 47 店破产重组，把预收的
  • 如果 要扩张/复制 → 则 先用一家样板店把坪效/师生比/续费率/爬坡周期跑成可复用标准模型，验证单店跑通再复制，绝不在没验证单元前就多店齐铺或放加

相关心智模型:
  • 能打 ≠ 能教 ≠ 能运营（师资三层断层）: 会打球、会教学、会运营是**三套互不蕴含的能力**——招到退役运动员只解决了第一层，教学法+持证是第二层，单店模型/续费/合规是第三层；这一行最深的坑是用第一层冒充后两层。
  • 续费率才是命门（不是满班，不是获客）: 单店生死线是**续费率 + 转介绍**，不是满班率或获客量——满班且高获客的店也会因续费塌方而死；「收钱 ≠ 课消 ≠ 确认收入」，预收费是受监管负债不是利润。

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "要让家长感知价值或驱动续费转介绍"
  "课包剩约 1/3 或出现成果节点（一次体测进步/一场比赛）"
  "续费率或出勤率跌破警戒线"
  "要扩张/复制"
)
declare -a RULE_ACTIONS=(
  "把测评数据做成可视化成长报告交付，而非只在期末口头汇报。这是跨 4 个 workflow（试听/教学/中考/续费）的元动作：测评不是合规动作，是「家长可感知结果」的生产线。案例：睿莱体测把 10 米折返/立定跳远做成成长曲线当续费弹药 (T02-S010)；资深人每节课就给家长一个进步反馈（视频/打卡），新人只在期末才汇报，续费率差一截 (T03-S010)"
  "立即启动续费动作在满意峰值顺势收，绝不到期才催费、更不靠打折逼单。案例：懒熊单店死亡案例续费率从约 46% 跌到接近 0 是直接死因，出勤率跌破 55% 是先兆 (T03-S020)；资深运营把续费前置到「孩子刚考级通过」时邀续费+转介绍，新人临到期才打电话已大概率流失 (T03-S010)"
  "先救留存再谈扩张/获客，绝不靠加大获客投放掩盖留存窟窿。案例：趣动旅程靠预收费扩张、黑天鹅下 47 店破产重组，把预收的续费款当利润花是经典死法 (T01-S028)；出勤率 59.8% 跌破 55% 即该停止开新店、先修单店模型 (T03-S020)"
  "先用一家样板店把坪效/师生比/续费率/爬坡周期跑成可复用标准模型，验证单店跑通再复制，绝不在没验证单元前就多店齐铺或放加盟。案例：动因式直营靠自研课程+地推先跑通再复制 (T02-S028)；YBDL 单店没跑透就加盟扩张、运营跟不上爆雷（总部空无一人、社保断缴）(T01-S010)"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "topic-1-decision"
fi
